 Ejemplos de Consumo
JavaScript/TypeScript
// Interface para el producto
interface Product {
  id: string;
  title: string;
  sku: string;
  priceCentsBase: number;
  currency: string;
  category?: {
    id: string;
    name: string;
  };
  presentations: Array<{
    code: string;
    name: string;
    factor: number;
    priceCents: number;
    available: number;
  }>;
}

// Interface para la respuesta paginada
interface ProductListResponse {
  products: Product[];
  total: number;
  page: number;
  limit: number;
  totalPages: number;
}

// Función para obtener productos
async function getProducts(params?: {
  page?: number;
  limit?: number;
  categoryId?: string;
  q?: string;
}): Promise<ProductListResponse> {
  const queryParams = new URLSearchParams();

  if (params?.page) queryParams.append('page', params.page.toString());
  if (params?.limit) queryParams.append('limit', params.limit.toString());
  if (params?.categoryId) queryParams.append('categoryId', params.categoryId);
  if (params?.q) queryParams.append('q', params.q);

  const response = await fetch(
    `http://localhost:3000/catalog/products?${queryParams}`
  );

  if (!response.ok) {
    throw new Error(`HTTP error! status: ${response.status}`);
  }

  return response.json();
}

// Función para obtener detalle de producto
async function getProduct(id: string): Promise<Product> {
  const response = await fetch(`http://localhost:3000/catalog/products/${id}`);

  if (!response.ok) {
    throw new Error(`HTTP error! status: ${response.status}`);
  }

  return response.json();
}

// Ejemplo de uso
async function main() {
  try {
    // Obtener lista de productos
    const productList = await getProducts({
      page: 1,
      limit: 10,
      q: 'agua'
    });

    console.log('Productos encontrados:', productList.total);
    console.log('Primer producto:', productList.products[0]);

    // Obtener detalle de un producto específico
    const productDetail = await getProduct(productList.products[0].id);
    console.log('Presentaciones disponibles:', productDetail.presentations);

  } catch (error) {
    console.error('Error:', error);
  }
}
