// src/pixel/PlayerSpec.ts (versión mínima para validar "idle")
// Mapa: . transp | K outline | S piel | s sombra piel
// W blanco | G gris claro | L lentes (negro)
// H hoodie | h luz hoodie | P pantalón | B bota | U suela
export const palette = [
  'transparent', '#1B1B1B', '#A06B4B', '#7C533B',
  '#FFFFFF', '#D9D9D9', '#21242C', '#2C313C',
  '#2A4669', '#121212', '#101010', '#BFBFBF'
]; // [0..11] => . K S s W G H h P B L U

const KEY: Record<string, number> = {
  '.':0, K:1, S:2, s:3, W:4, G:5, H:6, h:7, P:8, B:9, L:10, U:11
};
const toGrid = (rows: string[]) =>
  rows.map(r => r.trim().split('').map(ch => KEY[ch] ?? 0));

// ===== IDLE 24x24 (frente 3/4 derecha) =====
export const idle = toGrid([
